object DeepLinkHandler {
    const val SCHEME = "myapp"

    fun canHandle(uri: Uri?): Boolean {
        return uri != null && uri.scheme.equals(SCHEME, ignoreCase = true)
    }

    fun handle(context: Context, uri: Uri?): Boolean {
        if (!canHandle(uri)) return false

        val intent = createIntent(context, uri!!) ?: return false
        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        context.startActivity(intent)
        return true
    }

    fun createIntent(context: Context, uri: Uri): Intent? {
        val segments = uri.pathSegments ?: emptyList()
        if (segments.isEmpty()) return null

        return when (segments[0].lowercase()) {
            "profile" -> {
                val userId = segments.getOrNull(1)?.toLongOrNull() ?: return null
                Intent(context, ProfileActivity::class.java).apply {
                    putExtra(ProfileActivity.EXTRA_USER_ID, userId)
                    putExtra(EXTRA_DEEP_LINK_URI, uri.toString())
                }
            }
            "payment" -> {
                val action = segments.getOrNull(1)?.lowercase()
                if (action != "confirm") return null
                Intent(context, PaymentConfirmActivity::class.java).apply {
                    putExtra(EXTRA_DEEP_LINK_URI, uri.toString())
                }
            }
            else -> null
        }
    }

    const val EXTRA_DEEP_LINK_URI = "extra_deep_link_uri"
}

class DeepLinkRouterActivity : Activity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        route(intent)
        finish()
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        route(intent)
        finish()
    }

    private fun route(intent: Intent?) {
        val uri = intent?.data
        if (DeepLinkHandler.handle(this, uri)) return

        val fallback = Intent(this, MainActivity::class.java).apply {
            addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_SINGLE_TOP)
        }
        startActivity(fallback)
    }
}

